import React from 'react'


function ContactCard(props) {
  return (
    <div style={{
      width: "100%",
        maxWidth: "380px",
        margin: "10px auto",
        padding: "12px 16px",

        backgroundColor: "#ffffff",
        border: "1px solid #e0e0e0",
        borderRadius: "10px",

        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",

        boxShadow: "0 2px 6px rgba(0,0,0,0.05)"
    }}>
      <h3 style={{
          margin: "0",
          fontSize: "16px",
          fontWeight: "600"}}>{props.name}</h3>
      <p>{props.phone}</p>
      <p>{props.email}</p>
    </div>
  )
}

export default ContactCard;
